// Pico Blink LED - Raspberry Pi Pico Starter
// Blinks an external LED on GP15 and the built-in LED on GP25.

#include <Arduino.h>

const int LED_PIN = 15;       // External LED on GP15
const int BUILTIN_LED = 25;   // On-board LED on GP25

void setup() {
  pinMode(LED_PIN, OUTPUT);
  pinMode(BUILTIN_LED, OUTPUT);
  Serial.begin(115200);
  delay(100);
  Serial.println("Pico Blink LED started!");
}

void loop() {
  digitalWrite(LED_PIN, HIGH);
  digitalWrite(BUILTIN_LED, HIGH);
  Serial.println("LED ON");
  delay(1000);

  digitalWrite(LED_PIN, LOW);
  digitalWrite(BUILTIN_LED, LOW);
  Serial.println("LED OFF");
  delay(1000);
}
